import{_ as t,o,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Funnel","description":"","frontmatter":{"title":"Funnel","slug":"branch-funnel"},"headers":[],"relativePath":"marketer-hub/branch-funnel.md","filePath":"marketer-hub/branch-funnel.md"}'),r={name:"marketer-hub/branch-funnel.md"};function i(s,e,l,h,u,c){return o(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p><a href="https://branchdocs.app.link/e/funnel" target="_blank" rel="noreferrer">Funnel Analysis</a> simplifies multi-touch attribution reporting by visualizing the journey users take across your campaigns before converting. Instead of viewing only the last touchpoint before a conversion event, you can see the sequence of up to three interactions that led to each conversion.</p><p>Traditional last-touch attribution assigns full credit to the final touchpoint a user interacted with before converting. This model can potentially undervalue assisted touchpoints, which are touchpoints that play important roles earlier in the user journey but don&#39;t receive last-click credit.</p><p>Funnel addresses the limitations of last-touch attribution by tracking and displaying the full path users take, enabling you to understand how different interactions work together to drive conversions.</p><p>With Funnel, you can:</p><ul><li>View aggregated paths showing how users moved between touchpoints before converting.</li><li>Compare conversion paths across different dimensions such as campaigns, ad partners, and other attributes.</li><li>Analyze user journeys leading to any type of conversion event including installs, <a href="https://help.branch.io/developers-hub/docs/track-branch-events#:~:text=and%20Custom.-,Standard%20Events,-Standard%20Events%20have" target="_blank" rel="noreferrer">Branch Standard Events</a> like “Add to Cart”, or other <a href="https://help.branch.io/developers-hub/docs/track-branch-events#:~:text=COPY-,Custom%20Events,-Custom%20Events%20are" target="_blank" rel="noreferrer">Branch Custom Events</a> that you’ve defined.</li><li>Identify touchpoints that serve as effective entry points versus those that drive final conversions.</li><li>Understand the role of assisted touches, where channels may receive little last-touch credit but significantly influence user behavior.</li></ul><p>This path-level insight allows you to make more informed budget allocation decisions by accounting for the contribution of more touchpoints in the conversion journey, not just the final interaction.</p><h4 id="overlapping-lookback-windows" tabindex="-1">Overlapping lookback windows <a class="header-anchor" href="#overlapping-lookback-windows" aria-label="Permalink to &quot;Overlapping lookback windows&quot;">​</a></h4><p>Funnel supports overlapping lookback windows, allowing each partner to maintain its own attribution window length simultaneously.</p><p>In traditional attribution, when a user converts, the most recent touchpoint within an active window receives credit, effectively cutting off earlier partners from their full lookback periods.</p><p>With Funnel, each partner’s attribution window runs independently. If a user interacts with multiple ad partners and then converts after some partners’ windows have expired, the conversion is still attributed to the last partner whose window is still active. This is true even if that partner wasn’t the most recent touchpoint.</p><p>This approach ensures that partners with longer attribution windows can receive credit for conversions that occur throughout their full window period, providing a more accurate view of each partner’s contribution to user behavior over time.</p><p><strong>Setting attribution windows</strong></p><p>To set your global attribution windows at the app level:</p><ol><li>In Branch, select <strong>App Settings</strong> under the <strong>Configure</strong> section.</li><li>Select the <strong>Attribution</strong> tab.</li><li>Set your values for the various attribution types.</li></ol><p>To set custom attribution windows at the ad partner level:</p><ol><li>Select <strong>Ad Partners</strong> under the <strong>Configure</strong> section in Branch.</li><li>Find the ad partner you want to update in the list of ad partners.</li><li>Select the <strong>Attribution Windows</strong> tab.</li><li>Turn off the “<strong>Use ad partner attribution settings</strong>” toggle.</li><li>Set your own custom attribution window values for that ad partner’s attribution types.</li></ol><h3 id="packaging" tabindex="-1">Packaging <a class="header-anchor" href="#packaging" aria-label="Permalink to &quot;Packaging&quot;">​</a></h3><p>Funnel is available as part of certain Branch plans. For more information, please see our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing page</a> or <a href="https://branchdocs.app.link/e/funnel-contact-sales" target="_blank" rel="noreferrer">contact our Sales team</a>.</p><h2 id="use-funnel" tabindex="-1">Use Funnel <a class="header-anchor" href="#use-funnel" aria-label="Permalink to &quot;Use Funnel&quot;">​</a></h2><p>Generating a Funnel report will create both a visual component and a table-based component. These are generated using the same data, but they illustrate your user journeys in different ways.</p><p>All Funnel reports require three parameters:</p><ul><li>The <strong>date range</strong> you want to see user journeys for.</li><li>The event you consider the <strong>conversion event</strong> for your scenario.</li><li>A <strong>dimension</strong> to break out the user journeys by, such as ad partner or campaign.</li></ul><p>In addition to these three parameters, you have the option to add <strong>filters</strong> to the report. These are helpful if you only want to see certain campaigns, channels, features, etc.</p><h4 id="available-dimensions" tabindex="-1">Available dimensions <a class="header-anchor" href="#available-dimensions" aria-label="Permalink to &quot;Available dimensions&quot;">​</a></h4><p>The list of dimensions available for the required “compare by” field includes:</p><ul><li>Ad Partner</li><li>Ad Set ID</li><li>Ad Set Name</li><li>Campaign</li><li>Channel</li><li>Feature</li><li>Keyword</li></ul><h4 id="available-filters" tabindex="-1">Available filters <a class="header-anchor" href="#available-filters" aria-label="Permalink to &quot;Available filters&quot;">​</a></h4><p>The list of filters you can add to your report includes:</p><ul><li>Ad Partner</li><li>Ad Set ID</li><li>Ad Set Name</li><li>Campaign</li><li>Campaign ID</li><li>Channel</li><li>Feature</li><li>Keyword</li><li>OS</li><li>Geo Country Code</li></ul><h3 id="create-report" tabindex="-1">Create report <a class="header-anchor" href="#create-report" aria-label="Permalink to &quot;Create report&quot;">​</a></h3><p>To create a report in Funnel:</p><ol><li>Under <strong>Analysis</strong> in the left-side navigation of Branch, select <a href="https://branchdocs.app.link/e/funnel" target="_blank" rel="noreferrer"><strong>Funnel</strong></a>.</li><li>Select <strong>Dates</strong> and pick the date range you want to view user journeys for.</li><li>Select <strong>Show</strong> and decide which event you want to use as the conversion event for this report. For example: Installs, Purchases, Subscriptions, Impressions, etc.</li><li>Select <strong>Compare by</strong> and choose the <a href="./branch-funnel.html#available-dimensions">dimension</a> you want user journeys to be split by.</li><li>(Optional) Select <strong>Filters</strong> and add one or more <a href="./branch-funnel.html#available-filters">filters</a> to the report.</li></ol><p>Every selection you make will generate a new report immediately, so you can quickly observe how each selection is changing the report overall.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Based on the “compare by” dimension you chose in step 4, the report may populate with many user journeys. Filters help narrow results down even further, so you can focus on the user journeys you’re most interested in for a particular report.</p></div><h3 id="read-report-data" tabindex="-1">Read report data <a class="header-anchor" href="#read-report-data" aria-label="Permalink to &quot;Read report data&quot;">​</a></h3><p>Funnel reports have a strong visual component, as well as a structured table component. Use both views together to gain a more complete understanding of user engagement and drop-off points.</p><h4 id="read-visual-data" tabindex="-1">Read visual data <a class="header-anchor" href="#read-visual-data" aria-label="Permalink to &quot;Read visual data&quot;">​</a></h4><p>The top half of a Funnel report contains the report’s visual component, which takes the form of a traditional Sankey diagram. Sankey diagrams have two main parts:</p><ul><li><p><strong>Nodes</strong>: These represent the different touchpoints a user goes through on their journey to a conversion event. Funnel will show up to three nodes, or touchpoints, before a conversion. This information is displayed in the form of text. Please note that:</p><ul><li>[0] in front of a touchpoint means it is the <em>first</em> touchpoint in a user journey.</li><li>[1] in front of a touchpoint means it is the <em>second</em> touchpoint in a user journey.</li><li>[2] in front of a touchpoint means it is the <em>third</em> touchpoint in a user journey.</li></ul></li><li><p><strong>Links</strong>:These are the colored lines that connect touchpoints together. By following these flows, you can track groups of user journeys between touchpoints, and see where they diverge or drop off.</p></li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>By confirming that your date range and filters are appropriately selective, you can make sure that you’re viewing a manageable number of flows at once.</p></div><p>To read the visual diagram:</p><ol><li><p>View the far left batch of touchpoints, which all start with <code>[0]</code>. These are all the different original starting points your users had for the conversion event you selected.</p><ol><li>We recommend using parameters that result in Sankey diagrams with approximately 5-20 starting touchpoints.</li></ol></li><li><p>Hover directly over the text for a single touchpoint. Notice that:</p><ol><li><p>The color of the entire flow becomes opaque.</p></li><li><p>The flow itself may diverge into multiple paths, leading to other touchpoints and/or directly to the conversion event.</p><ol><li>All these paths are the same color, to illustrate that they originate from the same touchpoint.</li></ol></li><li><p>A text box pops up that has the following format: <strong>[Touchpoint number] Name of touchpoint (event): Number of events</strong>. For example: <code>[0] spring_trial_campaign (click): 821</code></p><ol><li>This means a click on the Spring Sign Up campaign was the <em>first</em> touchpoint (represented by the <code>[0]</code>) for 821 user journeys.</li></ol></li></ol></li><li><p>If the touchpoint you are hovering on splits into multiple paths of the same color, hover over one of the individual paths and notice:</p><ol><li><p>The path leads either to another touchpoint, or directly to a conversion event.</p></li><li><p>The text in the text box changes, so now the format is <strong>[First touchpoint number] Name of first touchpoint (event) → [Second touchpoint number] Name of second touchpoint (event): Number of events</strong>. For example: <code>[0] spring_trial_campaign (click) → [1] spring_registration_campaign (click): 98</code></p><ol><li>This means 98 user journeys started with a click on the Spring Sign Up campaign, then went on to click the Spring Get Started campaign.</li></ol></li></ol></li><li><p>Move inward to the second set of touchpoints, which all start with <code>[1]</code>. Hover directly over the text for one of these touchpoints. Notice that:</p><ol><li>There may be multiple paths that flow into this touchpoint. These are all the different places users are coming from to get to this touchpoint.</li><li>There may be multiple paths that flow out of this touchpoint, that lead either to other touchpoints or directly to the conversion event.</li></ol></li><li><p>Hover over the conversion event itself, on the rightmost side of the diagram. This will display the name of the conversion event, and the total number of times it occurred.</p></li></ol><h4 id="read-table-data" tabindex="-1">Read table data <a class="header-anchor" href="#read-table-data" aria-label="Permalink to &quot;Read table data&quot;">​</a></h4><p>The bottom half of a Funnel report is a structured table that distills the information from the visual component into a table with drill-down capabilities.</p><p>The table has two columns:</p><ul><li>The specific funnel (segment of a user journey), such as <code>[0] spring_trial_campaign (click) → [1] spring_registration_campaign (click)</code>.</li><li>The number of conversion events associated with that funnel.</li></ul><p>Each top-level row in the table will contain one of two things:</p><ul><li>Either the flow between two touchpoints and a <strong>plus symbol</strong>, OR</li><li>The flow between a touchpoint and the conversion event, with <em>no</em> plus symbol.</li></ul><p>If you see the <strong>plus symbol</strong>, this is because this particular segment does not lead directly to the conversion event. In other words, there are additional touchpoints between it and the conversion event.</p><p>To see these additional touchpoints, select the <strong>plus symbol</strong>. It will turn into a minus symbol, and will drill down into the row to show you how the paths from this touchpoint split off. Again, these paths can lead either to another touchpoint, or to a conversion event. The former will have another <strong>plus symbol</strong> you can select, to drill down further. The latter will not have any symbol, and will instead just show the number of user journeys associated with the parent row.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>The top-level rows in the table show the total number of conversion events associated with the starting touchpoints (which start with <code>[0]</code> ).</p><p>When you drill down into a row, the rows that appear below it have conversion event counts that will add up to the top-level row’s total number of conversion events.</p><p>If you drill down even further, the same principle applies. The number of conversion events added up together in the new rows that appear will equal the total number of conversion events for that segment.</p></div><h3 id="download-data" tabindex="-1">Download data <a class="header-anchor" href="#download-data" aria-label="Permalink to &quot;Download data&quot;">​</a></h3><p>To download your Funnel report’s visual Sankey data, select the <strong>three-line menu</strong> <strong>icon</strong> in the upper-right corner of the diagram section and choose to download the data as PNG, XLS, SVG (vector), or CSV.</p><p>To download your Funnel report’s structured table data, select the <strong>download icon</strong> from the upper-right corner of the table section. This will download the table data as a CSV.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p>Funnel is most effective when you start with a specific marketing question in mind.</p><p>Use the example questions below to get started with Funnel reports:</p><ul><li><p><strong>What is the typical path my users take across channels?</strong></p><ul><li>Set the dimension to Channel, and notice the order of the channels your users hop between before converting.</li></ul></li><li><p><strong>Are some of my campaigns better at initiating user journeys, while others are better at closing conversions?</strong></p><ul><li>Set the dimension to Campaign, and pick a specific date range, like your last quarter. See which campaigns work in the best combination with each other.</li></ul></li><li><p><strong>Is CRM stealing credit from paid advertising?</strong></p><ul><li>Set the dimension to Channel or Feature and look for patterns where Paid Search or Paid Advertising appear early in the journey, followed by Email or CRM touchpoints at the end. If you see this frequently, your CRM might be getting last-click credit for conversions where paid campaigns served as crucial assisted touches earlier in the journey.</li></ul></li><li><p><strong>What keywords appear in successful conversion paths, and at what touchpoints?</strong></p><ul><li>Set the dimension to Keyword and add the filter <code>Channel = Paid Search</code>. This will show you which keywords are best for early awareness versus conversion, which can help you refine your bidding strategy and keyword targeting.</li></ul></li><li><p><strong>Do users in one country require more touchpoints than another country?</strong></p><ul><li>Set the dimension to Campaign or Channel, and add filters for the specific Geo country codes you want to compare. This will show you the journey patterns within each market, revealing whether users in different regions have shorter or longer paths to conversion. Use this insight to tailor your regional marketing strategies and budget allocation.</li></ul></li><li><p><strong>Which ad partners contribute most effectively to conversions?</strong></p><ul><li>Set the dimension to Ad Partner, and make sure to adjust the date field to an appropriate time frame, like the last 30 days.</li></ul></li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What is Branch Funnel?</summary><p>Branch Funnel simplifies multi-touch attribution reporting by visualizing the complete journey users take across campaigns before converting.</p></details><details><summary>How does Funnel differ from traditional last-touch attribution?</summary><p>Funnel tracks and displays the actual path users take, allowing you to see up to three interactions that led to each conversion, rather than just the last touchpoint.</p></details><details><summary>What are assisted touches?</summary><p>Assisted touches are touchpoints that appear in the conversion path but aren&#39;t the final interaction before conversion. These touchpoints play important supporting roles in the user journey, such as initial awareness or mid-funnel engagement, even though they don&#39;t receive last-touch credit.</p></details><details><summary>Can I set custom attribution windows for ad partners?</summary><p>Yes. You can <a href="./attribution-windows-link-settings.html#configure-attribution-windows">set custom attribution windows</a> at the ad partner level by turning on the <strong>Use ad partner attribution settings</strong> toggle at the ad partner level in Branch.</p></details><details><summary>What parameters are required to generate a Funnel report?</summary><p>You need to specify the date range, the conversion event, and a dimension to break out the user journeys by.</p></details><details><summary>What types of conversion events can I analyze with Funnel?</summary><p>You can analyze various conversion events, including installs, Branch Standard Events like Add to Cart, or any other Branch Custom Events you’ve defined.</p></details><details><summary>Is Funnel available for all Branch plans?</summary><p>No, Funnel is only available as part of certain Branch plans. For more information, please <a href="https://branchdocs.app.link/e/funnel-contact-sales" target="_blank" rel="noreferrer">contact our Sales team</a> or reach out to your Account Manager.</p></details><details><summary>What visual representation does a Funnel report use?</summary><p>A Funnel report uses a traditional Sankey diagram to visually represent user journeys.</p></details><details><summary>How can I download my Funnel report data?</summary><p>You can download the visual Sankey data as PNG, XLS, SVG, or CSV, and the structured table data as CSV.</p></details><details><summary>Why don&#39;t the counts in Funnel match my other Branch report counts?</summary><p>Funnel shows the share of conversion paths rather than total counts. It also uses Branch&#39;s processing time rather than event timestamps in app timezones, which can cause differences compared to other reports.</p></details>',70)])])}const m=t(r,[["render",i]]);export{d as __pageData,m as default};
